$$, $$281f9215a6490ecbecf1bd5b67ca3582a75ab7bfa49d23982181b17ec46fd152$$, $${"A": "448891c8da83d8a303e798b3a25ef859f0af4ab6810bc850f8e9812f7aa0d325", "D": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "E": "ba3922e6bd76e8543bab26db345347cd75ad6f71e70706b36825a2f90b0561d9"}$$::jsonb, $$Budget J-Books/FY26/USAF/FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, 479, $$2026-05-07T23:56:37.011952+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604602F$$, 2026, $$The Armament Ordnance Development program funds open standards development and maturation for adoption by USAF, Joint, and Coalition weapon systems for
rapid integration, support, and operational use of the full range of armament capabilities. Weapons and weapon systems implementation of open armament interface
standards provides rapid integration of software-defined capabilities, reduces development timelines, lowers life-cycle cost, and ensures interoperability with emerging
capabilities. The Stores-Aircraft Interface project conducts stores-aircraft interface upgrades and standards development to include the Universal Armament Interface
(UAI).

This budget funds the Universal Armament Interface (UAI), a matured DAF-owned standard, that provides the continuous development, characterization, and
improvements required to ensure integration for current, future, and legacy munitions, ammunitions, delivery systems, and subsystems. The UAI delivers the standards
needed to integrate new weapon capabilities on platforms at the speed of software, independent of aircraft Operational Flight Program (OFPs) cycles; thus, reducing
costly regression testing for flight safety critical aircraft software. Planned implementations include Joint Strike Fighter (JSF/F-35), F-15EX, F-16 F-47, CCA, B-21, B-1,
B-2, B-52, MQ-9, Advanced Anti-Radiation Guided Missile - Extended Range (AARGM-ER), Joint Air-to-Surface Standoff Missile (JASSM), Joint Direct Attack Munition
(JDAM), SDB I & II, Stand-in Attack Weapon (SiAW), Long Range Anti-Ship Missile (LRASM), Grey Wolf, Select Precision Effects At Range Capability 3 (SPEAR3),
Joint Strike Missile (JSM), and Next-Generation Open Mission Services (NOMS) for mission planning.

Funding directly supports the development, enhancement, and sustainment of open armament standards to support the emerging needs of the above adopting platforms
and more. That ensures technical currency, support to coalition/joint interoperability efforts for weapons-platform interface, certification tools, and implementation
support to aircraft and weapons. Funding also supports the integration of the Common Flexible Weapon Interface (CFWI), providing a unified interface standard for air-
to-air and air-to-ground weapons. Additionally, funding supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability
prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs.

In October 2024, the Armament Ordnance Development program that managed this funding transitioned to the Architecture and Systems Engineering (ASE) group, Air
Force Life Cycle Management Center (AFLCMC), Wright Patterson AFB. In addition to this PE, the ASE group will continue execution of these related activities under
the following PEs:
0305206F / Airborne Reconnaissance Systems (672003 / Sensor Open Systems Architecture)
0605056F / Open Architecture Management (656060 / Standards Management)

This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds
